package com.example.sharereceiver;

import android.content.ClipData;
import android.content.Intent;
import android.net.Uri;
import android.os.Bundle;
import android.text.TextUtils;
import android.widget.ImageView;
import android.widget.LinearLayout;
import android.widget.ScrollView;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class ShareReceiverActivity extends AppCompatActivity {

    private TextView titleView;
    private TextView textView;
    private ImageView imageView;
    private TextView uriView;

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        ScrollView scrollView = new ScrollView(this);
        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        int padding = dp(16);
        root.setPadding(padding, padding, padding, padding);

        titleView = new TextView(this);
        titleView.setTextSize(20f);
        titleView.setText("Shared Content");

        textView = new TextView(this);
        textView.setTextSize(16f);

        imageView = new ImageView(this);
        imageView.setAdjustViewBounds(true);

        uriView = new TextView(this);
        uriView.setTextSize(14f);

        root.addView(titleView);
        root.addView(textView);
        root.addView(imageView);
        root.addView(uriView);

        scrollView.addView(root);
        setContentView(scrollView);

        handleShareIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleShareIntent(intent);
    }

    private void handleShareIntent(Intent intent) {
        textView.setText("");
        uriView.setText("");
        imageView.setImageDrawable(null);

        if (intent == null) {
            textView.setText("No shared content received.");
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        if (Intent.ACTION_SEND.equals(action)) {
            handleActionSend(intent, type);
        } else if (Intent.ACTION_SEND_MULTIPLE.equals(action)) {
            handleActionSendMultiple(intent, type);
        } else {
            textView.setText("Unsupported intent action: " + action);
        }
    }

    private void handleActionSend(Intent intent, String type) {
        StringBuilder builder = new StringBuilder();

        CharSequence subject = intent.getCharSequenceExtra(Intent.EXTRA_SUBJECT);
        CharSequence sharedText = intent.getCharSequenceExtra(Intent.EXTRA_TEXT);
        Uri streamUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);

        if (!TextUtils.isEmpty(subject)) {
            builder.append("Subject: ").append(subject).append("\n\n");
        }

        if (!TextUtils.isEmpty(sharedText)) {
            builder.append("Text: ").append(sharedText).append("\n\n");
        }

        if (streamUri == null) {
            ClipData clipData = intent.getClipData();
            if (clipData != null && clipData.getItemCount() > 0) {
                Uri clipUri = clipData.getItemAt(0).getUri();
                if (clipUri != null) {
                    streamUri = clipUri;
                }
            }
        }

        if (builder.length() == 0 && streamUri == null) {
            builder.append("No text or image found in shared content.");
        }

        textView.setText(builder.toString().trim());

        if (streamUri != null) {
            uriView.setText("Uri: " + streamUri);
            if (type != null && type.startsWith("image/")) {
                imageView.setImageURI(streamUri);
            }
        }
    }

    private void handleActionSendMultiple(Intent intent, String type) {
        StringBuilder builder = new StringBuilder();

        CharSequence subject = intent.getCharSequenceExtra(Intent.EXTRA_SUBJECT);
        CharSequence sharedText = intent.getCharSequenceExtra(Intent.EXTRA_TEXT);

        if (!TextUtils.isEmpty(subject)) {
            builder.append("Subject: ").append(subject).append("\n\n");
        }

        if (!TextUtils.isEmpty(sharedText)) {
            builder.append("Text: ").append(sharedText).append("\n\n");
        }

        java.util.ArrayList<Uri> uris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM);
        if (uris == null || uris.isEmpty()) {
            ClipData clipData = intent.getClipData();
            if (clipData != null) {
                uris = new java.util.ArrayList<>();
                for (int i = 0; i < clipData.getItemCount(); i++) {
                    Uri uri = clipData.getItemAt(i).getUri();
                    if (uri != null) {
                        uris.add(uri);
                    }
                }
            }
        }

        if (uris != null && !uris.isEmpty()) {
            builder.append("Received ").append(uris.size()).append(" item(s)\n");
            for (int i = 0; i < uris.size(); i++) {
                builder.append(i + 1).append(". ").append(uris.get(i)).append("\n");
            }
            if (type != null && type.startsWith("image/")) {
                imageView.setImageURI(uris.get(0));
            }
        } else if (builder.length() == 0) {
            builder.append("No shared content found.");
        }

        textView.setText(builder.toString().trim());
        uriView.setText("");
    }
    
    private int dp(int value) {
        return Math.round(value * getResources().getDisplayMetrics().density);
    }
}

